# lwext4_rust = { path = "../ext4fs", default-features = false }

# ★ 网络栈已完全自研(RyOS 后端,见 os/src/net/),不再依赖 smoltcp。
#   原 [workspace.dependencies.smoltcp](指向第三方 fork)为死依赖——源码零 `use smoltcp`、
#   Cargo.lock 无该包、无任何成员 crate 引用——已删除。

# profile 必须在 workspace 根才生效(子包里的会被忽略并告警)。debug=true 保留富 backtrace。
[profile.release]
debug = true
# ★ 内核 .text 逼近 RISC-V jal ±1MB 边界：编译器对【同一 CGU 内】的跨函数调用(如 pre_main→mm::init)
#   直发 jal，CGU 跨度一旦 >1MB 即 R_RISCV_JAL out of range(链接层 --no-relax 管不了编译器直发的 jal)。
#   拆细 CGU：每个 CU 极小→intra-CU 跨度都 <1MB 无越界、跨 CU 调用走可松弛远调(auipc+jalr,±2GB)。
#   代价仅少量跨 CU 内联机会(对内核可忽略)，随内核增长一劳永逸。
codegen-units = 256

//! The main module and entrypoint
//!
//! Various facilities of the kernels are implemented as submodules. The most
//! important ones are:
//!
//! - [`trap`]: Handles all cases of switching from userspace to the kernel
//! - [`task`]: Task management
//! - [`syscall`]: System call handling and implementation
//! - [`mm`]: Address map using SV39
//! - [`sync`]: Wrap a static data structure inside it so that we are able to access it without any `unsafe`.
//! - [`fs`]: Separate user from file system with some structures
//!
//! The operating system also starts in this module. Kernel code starts
//! executing from `entry.asm`, after which [`rust_main()`] is called to
//! initialize various pieces of functionality. (See its source code for
//! details.)
//!
//! We then call [`task::run_tasks()`] and for the first time go to
//! userspace.

